import React, { useState, useEffect } from 'react';
import { MemoryRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Layout } from './components/Layout';
import { Dashboard } from './pages/Dashboard';
import { Patients } from './pages/Patients';
import { Appointments } from './pages/Appointments';
import { Billing } from './pages/Billing';
import { Staff } from './pages/Staff'; 
import { Admissions } from './pages/Admissions';
import { Laboratory } from './pages/Laboratory';
import { Operations } from './pages/Operations';
import { Configuration } from './pages/Configuration';
import { Settings } from './pages/Settings'; 
import { Reports } from './pages/Reports'; 
import { Records } from './pages/Records';
import { Login } from './pages/Login';
import { User } from './types'; 
import { api } from './services/api';
import { useTranslation } from './context/TranslationContext';
import { AuthContext, useAuth } from './context/AuthContext';
import { HeaderProvider } from './context/HeaderContext';

function AppContent() {
  const { user, isAuthChecking } = useAuth();
  const { t } = useTranslation();

  if (isAuthChecking) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950 transition-colors">
        <div className="w-10 h-10 border-4 border-primary-100 border-t-primary-600 rounded-full animate-spin mb-4" />
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('app_loading')}</p>
      </div>
    );
  }

  if (!user) {
    return <Login />;
  }

  return (
    <Router>
      <HeaderProvider>
        <Layout>
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/patients" element={<Patients />} />
            <Route path="/appointments" element={<Appointments />} />
            <Route path="/admissions" element={<Admissions />} /> 
            <Route path="/laboratory" element={<Laboratory />} /> 
            <Route path="/operations" element={<Operations />} /> 
            <Route path="/billing" element={<Billing />} />
            <Route path="/hr" element={<Staff />} /> 
            <Route path="/reports" element={<Reports />} /> 
            <Route path="/records" element={<Records />} /> 
            <Route path="/settings" element={<Settings />} /> 
            <Route path="/configuration" element={<Configuration />} /> 
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </Layout>
      </HeaderProvider>
    </Router>
  );
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true);

  useEffect(() => {
    const checkAuth = async () => {
      const token = localStorage.getItem('token');
      if (token) {
        try {
          const userData = await api.me();
          setUser(userData);
        } catch (e: any) {
          // Silent handling for common 401 (expired session) during initial load
          if (e.response?.status !== 401) {
            console.error("Auth check failed:", e);
          }
          localStorage.removeItem('token');
          setUser(null);
        }
      }
      setIsAuthChecking(false);
    };
    checkAuth();

    const handleAuthExpired = () => {
      localStorage.removeItem('token');
      setUser(null);
    };
    window.addEventListener('auth:expired', handleAuthExpired);
    return () => window.removeEventListener('auth:expired', handleAuthExpired);
  }, []);

  const login = (userData: User, token: string) => {
    localStorage.setItem('token', token);
    setUser(userData);
  };

  const logout = () => {
    localStorage.removeItem('token');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, isAuthChecking, login, logout }}>
      <AppContent />
    </AuthContext.Provider>
  );
}

import React from 'react';
import type { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary component to catch rendering errors in the component tree.
 */
/* Fix: Explicitly extending React.Component with typed props and state to ensure members like state, props, and setState are correctly inherited and recognized by TypeScript. Using React.Component is more robust than importing Component separately in some environments. */
export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    /* Fix: Initializing the state property inherited from React.Component. */
    this.state = {
      hasError: false,
      error: null
    };
  }

  /**
   * Static method to update state when an error occurs during rendering.
   */
  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  /**
   * Lifecycle method to log error details.
   */
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  /**
   * Resets the error state to allow the application to attempt re-rendering.
   */
  public handleReload = () => {
    /* Fix: Calling setState which is a member of React.Component. */
    this.setState({ hasError: false, error: null });
  }

  public render(): ReactNode {
    /* Fix: Accessing state which is a member of React.Component. */
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {/* Fix: Accessing error from state which is a member of React.Component. */}
            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    /* Fix: Accessing props.children which is a member of React.Component. */
    return this.props.children;
  }
}

const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');
const { ROLE_PERMISSIONS } = require('../utils/rbac_backend_mirror');

// Use an absolute path relative to the backend directory for consistency
const dbPath = process.env.DB_PATH || path.resolve(__dirname, '../../allcare.db');

// Ensure the directory exists
const dbDir = path.dirname(dbPath);
if (!fs.existsSync(dbDir)) {
  fs.mkdirSync(dbDir, { recursive: true });
}

console.log(`[Database] Target path: ${dbPath}`);

let db;
try {
  db = new Database(dbPath);
  db.pragma('journal_mode = WAL'); // Improved concurrency
  db.pragma('synchronous = NORMAL'); 
  db.pragma('foreign_keys = ON');
} catch (e) {
  console.error("CRITICAL: Failed to open SQLite database:", e);
  process.exit(1);
}

const initDB = (forceReset = false) => {
  if (forceReset) {
    console.log('[Database] Resetting data...');
    try {
      db.close();
      if (fs.existsSync(dbPath)) fs.unlinkSync(dbPath);
      db = new Database(dbPath);
      db.pragma('journal_mode = WAL');
    } catch (e) {
      console.error("[Database] Reset failed:", e);
    }
  }

  console.log('[Database] Verifying schema...');

  // --- Core Tables ---
  db.prepare(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
