import React, { Component } from 'react';
import type { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary component to catch rendering errors in the component tree.
 */
/* Fix: Extending Component directly and using class property for state initialization to resolve property existence errors and ensure proper inheritance of state, props, and setState in some TypeScript environments. */
export class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  /**
   * Static method to update state when an error occurs during rendering.
   */
  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  /**
   * Lifecycle method to log error details.
   */
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  /**
   * Resets the error state to allow the application to attempt re-rendering.
   */
  public handleReload = () => {
    /* Fix: setState is correctly inherited from Component. */
    this.setState({ hasError: false, error: null });
  }

  public render(): ReactNode {
    /* Fix: state is correctly inherited from Component. */
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {/* Fix: Accessing error property from the inherited state object. */}
            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    /* Fix: children is correctly accessed from the inherited props object. */
    return this.props.children;
  }
}

import axios from 'axios';

// Helper to determine the correct base URL based on the current environment
const getBaseUrl = () => {
  // Use relative path '/api' to ensure same-origin requests work across all environments.
  // This is critical for Railway and other proxy-based deployments.
  return '/api';
};

const client = axios.create({
  baseURL: getBaseUrl(),
  headers: { 
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  },
  // Increased timeout to 60s to handle backend cold starts on Railway/Render/etc.
  timeout: 60000, 
});

client.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers = config.headers || {};
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

client.interceptors.response.use(
  (response) => response.data,
  async (error) => {
    const { config, response } = error;

    // 1. Handle Rate Limiting (429)
    if (response?.status === 429 && !config._retry) {
      config._retry = true;
      console.warn('[API] Rate limit hit, retrying in 2s...');
      await new Promise(resolve => setTimeout(resolve, 2000));
      return client(config);
    }

    // 2. Handle Network Errors / Backend Unreachable
    // This specifically targets ERR_NETWORK, timeout, and cases where response is undefined
    const isNetworkError = error.code === 'ERR_NETWORK' || error.code === 'ECONNABORTED' || !error.response;

    if (isNetworkError && !config._retryNetwork) {
        config._retryNetworkCount = (config._retryNetworkCount || 0) + 1;
        const MAX_RETRIES = 5; 

        if (config._retryNetworkCount <= MAX_RETRIES) {
            const delay = 2500; // Slightly longer delay for retries
            const targetUrl = config.url ? (config.baseURL ? config.baseURL + config.url : config.url) : 'unknown';

            console.log(`[API] Backend unreachable at ${targetUrl}. Attempt ${config._retryNetworkCount}/${MAX_RETRIES}. Retrying in ${delay}ms...`);

            await new Promise(resolve => setTimeout(resolve, delay));
            return client(config);
        }
    }

    // 3. Handle Session Expiry (401)
    if (error.response?.status === 401) {
      const isLoginRequest = config.url?.includes('/auth/login');
      const isPublicRequest = config.url?.includes('/config/settings/public');

      if (!isLoginRequest && !isPublicRequest) {
        console.warn('[API] Session expired. Clearing token.');
        localStorage.removeItem('token');
        window.dispatchEvent(new Event('auth:expired'));
      }
    } 

    // 4. Enhance Error Message for User
    if (isNetworkError) {
        const isBackgroundPolling = config.url?.includes('/notifications') || config.url?.includes('/config/health');
        if (!isBackgroundPolling) {
            const enhancedError = new Error('Network Error: The hospital backend is currently unreachable. This may be due to a server restart or network connection issues.');
            (enhancedError as any).code = 'ERR_NETWORK';
            (enhancedError as any).isNetworkError = true;
            return Promise.reject(enhancedError);
        }
    }

    return Promise.reject(error);
  }
);

