import React from 'react';
import type { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary component to catch rendering errors in the component tree.
 */
/* Fix: Explicitly using React.Component and initializing state in a constructor to ensure proper inheritance of setState and props across different TypeScript environments. */
export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  /**
   * Static method to update state when an error occurs during rendering.
   */
  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  /**
   * Lifecycle method to log error details.
   */
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  /**
   * Resets the error state to allow the application to attempt re-rendering.
   */
  public handleReload = () => {
    /* Fix: setState is correctly inherited from React.Component. */
    this.setState({ hasError: false, error: null });
  }

  public render(): ReactNode {
    /* Fix: state is correctly inherited from React.Component. */
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {/* Fix: Accessing error property from the correctly typed state. */}
            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    /* Fix: children is correctly accessed from the inherited props object. */
    return this.props.children;
  }
}

import axios from 'axios';

/**
 * PRODUCTION_URL: Your deployed backend URL.
 * In production (on Railway), the frontend is served by the backend, so relative '/api' works.
 * In dev/sandbox (like AI Studio), we fallback to this absolute URL.
 */
const PRODUCTION_URL = 'https://allcare.up.railway.app';

const getBaseUrl = () => {
  const host = window.location.hostname;
  const isLocal = host === 'localhost' || host === '127.0.0.1';
  const isSandbox = host.includes('aistudio.google.com') || host.includes('webcontainer.io');

  // If we're in a sandbox or local dev, and not explicitly on the production domain,
  // we point to the absolute production URL to ensure the API is reachable.
  if (isSandbox || (isLocal && !window.location.port.includes('8080'))) {
    return `${PRODUCTION_URL}/api`;
  }

  // Standard relative path for production or correctly proxied environments
  return '/api';
};

const client = axios.create({
  baseURL: getBaseUrl(),
  headers: { 
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  },
  // High timeout (60s) to handle Railway cold starts
  timeout: 60000, 
});

client.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers = config.headers || {};
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

client.interceptors.response.use(
  (response) => response.data,
  async (error) => {
    const { config, response } = error;

    // 1. Handle Rate Limiting (429)
    if (response?.status === 429 && !config._retry) {
      config._retry = true;
      console.warn('[API] Rate limit reached. Waiting 2s before retry...');
      await new Promise(resolve => setTimeout(resolve, 2000));
      return client(config);
    }

    // 2. Handle Network Errors / Cold Starts
    const isNetworkError = error.code === 'ERR_NETWORK' || error.code === 'ECONNABORTED' || !error.response;

    if (isNetworkError) {
        config._retryCount = (config._retryCount || 0) + 1;
        const MAX_RETRIES = 10; // Increased retries for cold starts

        if (config._retryCount <= MAX_RETRIES) {
            const delay = 3000; // 3 second delay between retries
            const targetUrl = config.url ? (config.baseURL ? config.baseURL + config.url : config.url) : 'unknown';

            console.log(`[API] Connection attempt ${config._retryCount}/${MAX_RETRIES} failed at ${targetUrl}. The server might be waking up. Retrying in ${delay}ms...`);

            await new Promise(resolve => setTimeout(resolve, delay));
            return client(config);
        }
    }

    // 3. Handle Session Expiry (401)
    if (error.response?.status === 401) {
      const isAuthRequest = config.url?.includes('/auth/login') || config.url?.includes('/auth/me');
      if (!isAuthRequest) {
        console.warn('[API] Session expired. Clearing credentials.');
        localStorage.removeItem('token');
        window.dispatchEvent(new Event('auth:expired'));
      }
    } 

    // 4. Detailed Error for UI
    if (isNetworkError) {
        const enhancedError = new Error('Network Connectivity Error: The hospital management backend is unreachable. This usually happens during a server restart or "cold start" on hosting platforms. Please wait 30 seconds and try again.');
        (enhancedError as any).isNetworkError = true;
        return Promise.reject(enhancedError);
    }

    return Promise.reject(error);
  }
);

const get = (url: string) => client.get(url) as Promise<any>;
const post = (url: string, data?: any, config?: any) => client.post(url, data, config) as Promise<any>;
const put = (url: string, data?: any) => client.put(url, data) as Promise<any>;
const del = (url: string) => client.delete(url) as Promise<any>;

