const path = require('path');
// Load .env from project root if it exists, otherwise default (backend/.env)
require('dotenv').config({ path: path.resolve(__dirname, '../.env') });

const express = require('express');
const cors = require('cors');
const helmet = require('helmet');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');
const { initDB, db } = require('./src/config/database');
const apiRoutes = require('./src/routes/api');

const app = express();

// Port Selection Strategy for Cloud Providers (Railway, Render, Heroku)
const PORT = process.env.PORT || 8080; 

app.set('trust proxy', 1);

// Initialize DB
try {
  initDB();
  console.log('[Init] Database loaded and verified.');
} catch (error) {
  console.error('[Error] Critical Database Initialization Failure:', error);
}

// Global Middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'", "'unsafe-inline'", "'unsafe-eval'", "https://cdn.tailwindcss.com", "https://esm.sh"],
      styleSrc: ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com", "https://cdn.tailwindcss.com"],
      fontSrc: ["'self'", "https://fonts.gstatic.com", "data:"],
      connectSrc: ["'self'", "https://esm.sh", "*"],
      imgSrc: ["'self'", "data:", "https:", "http:"],
      frameAncestors: ["'self'", "*"], 
      objectSrc: ["'none'"],
    },
  },
  crossOriginResourcePolicy: { policy: "cross-origin" },
  crossOriginEmbedderPolicy: false
}));

// Permissive CORS for demo/preview environments
app.use(cors({
    origin: '*', 
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization', 'Accept']
}));

app.use(morgan('combined')); // Detailed logging for debugging Railway hits
app.use(express.json());

// Request Debugger (Helpful for diagnosing "Backend Unreachable" in AI Studio)
app.use((req, res, next) => {
    console.log(`[Request] ${req.method} ${req.originalUrl} from ${req.ip}`);
    next();
});

// Rate Limiting
const apiLimiter = rateLimit({
  windowMs: 5 * 60 * 1000, 
  max: 10000, 
  standardHeaders: true,
  legacyHeaders: false,
});
app.use('/api', apiLimiter);

// API Routes
app.use('/api', apiRoutes);

// Health Check
app.get('/health', (req, res) => {
  res.json({ 
    status: 'online', 
    timestamp: new Date().toISOString(),
    database: db && db.open ? 'connected' : 'disconnected' 
  });
});

// Static Assets
const publicPath = path.join(__dirname, 'public');
app.use(express.static(publicPath));

// catch-all for SPA
app.get('*', (req, res) => {
  if (req.accepts('html')) {
    const indexPath = path.join(publicPath, 'index.html');
    res.sendFile(indexPath, (err) => {
        if (err && !res.headersSent) {
            res.status(404).send('Frontend application assets not found. Please run build script.');
        }
    });
  } else {
    res.status(404).json({ error: 'Not found' });
  }
});

// Global Error Handler
app.use((err, req, res, next) => {
  console.error('[Fatal] Internal Server Error:', err);
  if (res.headersSent) return next(err);
  res.status(500).json({ error: 'Internal Server Error', details: err.message });
});

// Bind to 0.0.0.0 for external accessibility in containers
const server = app.listen(PORT, '0.0.0.0', () => {
  console.log(`[Server] AllCare HMS Backend running on port ${PORT}`);
  console.log(`[Server] Accessible at http://0.0.0.0:${PORT}`);
});

// Graceful Shutdown
const shutdown = () => {
  console.log('[Shutdown] Terminating server process...');
  server.close(() => {
    console.log('[Shutdown] HTTP connections closed.');
    try {
        if (db && db.open) {
            db.close();
            console.log('[Shutdown] Database connection finalized.');
        }
    } catch (e) {
        console.error('[Error] Shutdown cleanup failed:', e);
    }
    process.exit(0);
  });
};

process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);

import React, { Component } from 'react';
import type { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary component to catch rendering errors in the component tree.
 */
/* Fix: Using named Component import to ensure proper type inheritance from React's base component class. */
export class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  /* Fix: Initializing state directly as a class property to ensure it's correctly typed and recognized by the TypeScript compiler. */
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  /**
   * Static method to update state when an error occurs during rendering.
   */
  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  /**
   * Lifecycle method to log error details.
   */
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  /**
   * Resets the error state to allow the application to attempt re-rendering.
   */
  public handleReload = () => {
    /* Fix: setState is now correctly recognized as an inherited method from Component. */
    this.setState({ hasError: false, error: null });
  }

  public render(): ReactNode {
    /* Fix: state property is now correctly recognized via inheritance. */
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {/* Fix: safely accessing error property from the now-recognized state object. */}
            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    /* Fix: props property is now correctly recognized via inheritance. */
    return this.props.children;
  }
}
